// Parse the JSON_REPORT block from the script stdout and decide whether to notify.
const out = $input.first().json.stdout || '';
const m = out.match(/JSON_REPORT_BEGIN\n([\s\S]*?)\nJSON_REPORT_END/);
if (!m) return [{ json: { ok: false, reason: 'no JSON report in stdout' } }];
const report = JSON.parse(m[1]);
return [{ json: { ok: true, newlyReplaced: report.counts.newlyReplaced, report } }];
